def parse_nombre(raw):
    tokens = raw.strip().split()
    if len(tokens) < 2:
        return {"raw": raw, "given": None, "ap1": None, "ap2": None, "status": "review"}
    if len(tokens) == 2:
        return {"raw": raw, "given": tokens[0], "ap1": tokens[1], "ap2": None, "status": "review"}
    return {"raw": raw, "given": " ".join(tokens[:-2]), "ap1": tokens[-2], "ap2": tokens[-1], "status": "ok"}
for s in ["Ana Quispe Huamán", "Luis Pérez", "X"]:
    print(parse_nombre(s))

def normalize_email(raw: str) -> str:
    s = raw.strip().casefold()
    if s.count('@') != 1 or any(ch.isspace() for ch in s):
        raise ValueError('email requiere un @ y cero espacios')
    local, domain = s.split('@')
    if not local or not domain:
        raise ValueError('email requiere local y dominio')
    return s
print(normalize_email('  Ana+tag@Ejemplo.PE '))

def normalize_phone_pe(raw: str) -> str:
    return ''.join(c for c in raw if c.isdigit())
print(normalize_phone_pe('+51 999 000 111'))

def classify_contact(email_raw, phone_raw):
    errors = []
    s = email_raw.strip().casefold()
    email = s if s.count('@') == 1 else None
    if email is None:
        errors.append('email_review')
    phone = ''.join(c for c in phone_raw if c.isdigit())
    if len(phone) < 9:
        errors.append('phone_review')
        phone = phone or None
    return {'email': email, 'phone': phone, 'status': 'ok' if not errors else 'review', 'errors': errors}
print(classify_contact('a@b.pe', '+51 999000111'))
print(classify_contact('malo', '12'))

def tokens(s: str) -> set:
    return set(s.casefold().split())
def token_jaccard(a: str, b: str) -> float:
    A, B = tokens(a), tokens(b)
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
print(round(token_jaccard('Juan Perez', 'Juan P. Perez'), 3))
print(round(token_jaccard('Ana Quispe', 'Luis Huamán'), 3))

import unicodedata
def norm(s):
    return ' '.join(unicodedata.normalize('NFC', s).casefold().split())
print(norm('  José  PÉREZ ') == norm('José perez'))

def tokens(s):
    return set(s.casefold().split())
def jaccard(a,b):
    A,B=tokens(a),tokens(b)
    if not A and not B: return 1.0
    if not A or not B: return 0.0
    return len(A&B)/len(A|B)
score = jaccard('María del Carmen', 'Maria Carmen')
decision = 'exact' if score == 1 else ('review' if score >= 0.3 else 'no_match')
print(round(score,3), decision)

def evidence_pack(raw_a, raw_b, score, decision, reason):
    return {'raw_a': raw_a, 'raw_b': raw_b, 'score': score, 'decision': decision, 'reason': reason}
